import matplotlib.gridspec as gridspec

# Second order system transfer function:
# H(s) = wn^2 / (s^2 + 2*zeta*wn*s + wn^2)
# In frequency domain (s = j*omega):
# H(jw) = wn^2 / ((jw)^2 + 2*zeta*wn*(jw) + wn^2)
# Normalized: H(ju) = 1 / (1 - u^2 + 2*j*zeta*u)  where u = w/wn

print("Generating Bode plot of second order system with different damping factors...")

# Damping ratios to plot
damping_factors = [0.1, 0.2, 0.3, 0.5, 0.707, 1.0, 2.0]

