u = np.logspace(-2, 2, 2000)  # u = w/wn from 0.01 to 100

# Colors for different damping factors
colors = ['#e74c3c', '#e67e22', '#f1c40f', '#2ecc71', '#3498db', '#9b59b6', '#1abc9c']

# Create figure with two subplots
fig = plt.figure(figsize=(12, 9))
fig.patch.set_facecolor('#1a1a2e')

gs = gridspec.GridSpec(2, 1, hspace=0.4)
ax_mag = fig.add_subplot(gs[0])
